    if (m && ALL_MOTTOS.find((x) => x.id === m)) setMottoId(m);
    const a = p.get("alter");
    if (a) {
      const v = parseInt(a);
      if (v >= 3 && v <= 12) setAge(v);
    }
    const g = p.get("gaeste");
    if (g) {
      const v = parseInt(g);
      if (v >= 1 && v <= 20) setGuests(v);
    }
    const modus = p.get("modus");
    const thema = p.get("thema");
    if (modus === "schatzsuche") {
      setSzActive(true);
      if (!thema) {
        const mid = p.get("motto") || loadState("mottoId", null);
        if (mid && SZ_THEMES.find((t) => t.id === mid)) setSzThemeId(mid);
      }
    }
